import xml.etree.ElementTree as ET
import os

def validate_xml_file(xml_file_path, schema_file_path=None):
    if not os.path.exists(xml_file_path):
        raise FileNotFoundError(f"XML file not found: {xml_file_path}")
    if not os.path.isfile(xml_file_path):
        raise ValueError(f"Provided path is not a file: {xml_file_path}")

    try:
        # Attempt to parse the XML document
        tree = ET.parse(xml_file_path)
        root = tree.getroot()

        # Basic check if it's an empty or malformed XML
        if root is None and ET.tostring(tree.getroot(), encoding='utf8', method='xml').strip() == b'':
             raise ValueError("XML file is empty or contains no root element.")

        # If a schema is provided, attempt to validate against it
        if schema_file_path:
            if not os.path.exists(schema_file_path):
                raise FileNotFoundError(f"Schema file not found: {schema_file_path}")
            if not os.path.isfile(schema_file_path):
                raise ValueError(f"Provided schema path is not a file: {schema_file_path}")

            # For schema validation, lxml is typically used as the standard library
            # ElementTree does not directly support DTD/XSD validation.
            # This part assumes lxml is available if schema validation is requested.
            # If lxml is not installed, this will raise an ImportError.
            try:
                from lxml import etree
            except ImportError:
                raise ImportError("lxml library is required for schema validation. Please install it (`pip install lxml`).")

            xmlschema_doc = etree.parse(schema_file_path)
            xmlschema = etree.XMLSchema(xmlschema_doc)

            # Re-parse the XML with lxml for validation
            lxml_doc = etree.parse(xml_file_path)
            xmlschema.assertValid(lxml_doc) # Will raise an exception if invalid

        return True, "XML document is valid."

    except ET.ParseError as e:
        return False, f"XML parsing error: {e}"
    except etree.m_parser.XMLSyntaxError as e: # lxml specific syntax error
        return False, f"XML syntax error (lxml): {e}"
    except etree.SchemaError as e: # lxml specific schema error
        return False, f"XML schema validation error (lxml): {e}"
    except etree.DocumentInvalid as e: # lxml specific validation error
        return False, f"XML document is invalid according to schema (lxml): {e}"
    except FileNotFoundError as e:
        return False, str(e)
    except ValueError as e:
        return False, str(e)
    except ImportError as e:
        return False, str(e)
    except Exception as e:
        return False, f"An unexpected error occurred: {e}"